```javascript
function jumpToToday() {
  var sheet = SpreadsheetApp.getActiveSpreadsheet().getActiveSheet();
  var dateRange = sheet.getRange("A1:A");
  var today = new Date();
  today.setHours(0, 0, 0, 0);
  var todayCell = dateRange.createTextFinder(today.toDateString()).findNext();
  if (todayCell) {
    todayCell.activate();
  }
}
```

