function goToTodayKeepRow () {
  var ass = SpreadsheetApp.getActiveSpreadsheet ();
  var as = ass.getActiveSheet ();
  var today = new Date ();
  today.setHours (0,0,0,0);
  var datesRange = as.getRange (1, 1, 1, as.getLastColumn ());
