    public GameObject prefab3D;
    public GameObject prefabStep;
    public GameObject prefabInteraction;

    void Start()
    {
        StartCoroutine(ParseDocument());
    }

    IEnumerator ParseDocument()
    {
        Words words = new Words(Application.dataPath + "/Document.txt");
        foreach (Word word in words.Words)
        {
            string label = word.Text.Trim().ToLower();

            if (label == "[2d]")
            {
                Create2DAsset(word.NextWord);
            }
            else if (label == "[3d]")
            {
                Create3DAsset(word.NextWord);
            }
            else if (IsHeader(word.Text))
            {
                CreateStep(word.Text);
            }
            else if (IsInteraction(word.Text))
            {
                CreateInteraction(word.Text);
            }

            word.Skip(2); // Skip 2 spaces to move to the next word
        }

        yield return null;
    }

    bool IsHeader(string text)
    {
        // Add your header identification logic here
        return text.StartsWith("#");
    }

    bool IsInteraction(string text)
    {
        // Add your interaction identification logic here
        return text.StartsWith("[Interaction]");
    }

    void Create2DAsset(string assetName)
    {
        // Instantiate 2D asset prefab and set name
        GameObject instance = Instantiate(prefab2D, Vector3.zero, Quaternion.identity);
        instance.name = assetName;
    }

    void Create3DAsset(string assetName)
