using System.Collections;
using System.Collections.Generic;
using System.Xml;
using UnityEngine;

public class WordDocumentParser : MonoBehaviour
{
    public string documentPath;
    public GameObject prefab2D;
    public GameObject prefab3D;
    public GameObject prefabStep;
    public GameObject prefabInteraction;

    private void Start()
    {
        StartCoroutine(ParseDocument());
    }

    private IEnumerator ParseDocument()
    {
