```javascript
import { parse, stringify } from 'query-string';

export function addQueryParams(baseUrl, queryParams) {
  const parsedUrl = parse(baseUrl, { parseQueryString: true });
  const mergedQueryParams = { ...parsedUrl.query, ...queryParams };
  const updatedUrl = {
    ...parsedUrl,
    query: mergedQueryParams,
  };

  return stringify(updatedUrl);
}
